import { useEffect, useState } from 'react';
import { Link, Navigate, useLocation, useNavigate } from 'react-router-dom';
import useAuth from '../context/useAuth';
import useCart from '../context/useCart';
import useLanguage from '../context/useLanguage';
import useDocumentTitle from '../hooks/useDocumentTitle';

const REMEMBERED_EMAIL_KEY = 'tienda_react_remembered_email';
const SESSION_EXPIRED_STORAGE_KEY = 'tienda_react_auth_session_expired';
const SESSION_EXPIRED_REDIRECT_STORAGE_KEY = 'tienda_react_auth_session_expired_redirect';

/**
 * Ensures redirect path stays inside app routes.
 * @param {string} value
 * @returns {string}
 */
function sanitizeRedirectPath(value) {
  const raw = String(value || '').trim();
  if (!raw.startsWith('/') || raw.startsWith('//') || /[\r\n\t]/.test(raw)) {
    return '/';
  }
  return raw;
}

/**
 * Reads and clears expired-session metadata in one pass.
 * @returns {{ expired: boolean, redirectPath: string }}
 */
function consumeExpiredSessionContext() {
  try {
    const expired = localStorage.getItem(SESSION_EXPIRED_STORAGE_KEY) === '1';
    const redirectPath = expired
      ? sanitizeRedirectPath(localStorage.getItem(SESSION_EXPIRED_REDIRECT_STORAGE_KEY))
      : '/';

    localStorage.removeItem(SESSION_EXPIRED_STORAGE_KEY);
    localStorage.removeItem(SESSION_EXPIRED_REDIRECT_STORAGE_KEY);

    return { expired, redirectPath };
  } catch {
    return { expired: false, redirectPath: '/' };
  }
}

function getSavedEmail() {
  try {
    return localStorage.getItem(REMEMBERED_EMAIL_KEY) || '';
  } catch {
    return '';
  }
}

/**
 * Login page for client-side authenticated access.
 * Accessibility: fields are labeled and errors are announced.
 */
export default function Login() {
  const { t } = useLanguage();
  // WCAG 2.4.2: descriptive page title announced by screen readers on navigation.
  useDocumentTitle(t('common.login'));
  const { isAuthenticated, login } = useAuth();
  const { showToast } = useCart();
  const location = useLocation();
  const navigate = useNavigate();

  const [form, setForm] = useState({ email: getSavedEmail(), password: '' });
  const [error, setError] = useState('');
  const [fieldErrors, setFieldErrors] = useState({});
  const [touched, setTouched] = useState({});
  const [showPassword, setShowPassword] = useState(false);
  const [rememberEmail, setRememberEmail] = useState(() => Boolean(getSavedEmail()));
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [expiredSessionContext] = useState(consumeExpiredSessionContext);

  useEffect(() => {
    if (expiredSessionContext.expired) {
      showToast(t('common.sessionClosedInactive'), 'info');
    }
  }, [expiredSessionContext.expired, showToast, t]);

  const redirectTo = location.state?.from?.pathname || expiredSessionContext.redirectPath || '/';

  if (isAuthenticated) {
    return <Navigate to={redirectTo} replace />;
  }

  /** Validates one login field and returns an inline-friendly message. */
  const validateField = (name, value) => {
    if (name === 'email') {
      const safeValue = value.trim();
      if (!safeValue) return t('common.requiredEmail');
      if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(safeValue)) return t('common.invalidEmail');
      return undefined;
    }

    if (name === 'password') {
      if (!value) return t('common.requiredPassword');
      if (value.length < 8) return t('common.passwordMin');
      return undefined;
    }

    return undefined;
  };

  /** Handles login form submission and redirects to previous route. */
  const handleSubmit = async (e) => {
    e.preventDefault();
    if (isSubmitting) {
      return;
    }

    const nextErrors = {
      email: validateField('email', form.email),
      password: validateField('password', form.password),
    };

    setTouched({ email: true, password: true });
    setFieldErrors(nextErrors);

    if (nextErrors.email || nextErrors.password) {
      return;
    }

    setIsSubmitting(true);
    const result = await login(form);

    if (!result.ok) {
      const message = result.error || t('common.signInFailed');
      setError(message);
      showToast(message, 'error');
      setIsSubmitting(false);
      return;
    }

    setError('');
    const roleLabel = result.role === 'admin' ? t('common.roleAdmin').toLowerCase() : t('common.roleClient').toLowerCase();
    showToast(t('common.loginAs', { role: roleLabel }), 'success');
    try {
      if (rememberEmail) {
        localStorage.setItem(REMEMBERED_EMAIL_KEY, form.email.trim());
      } else {
        localStorage.removeItem(REMEMBERED_EMAIL_KEY);
      }
    } catch { /* ignore */ }
    const targetPath = redirectTo || (result.role === 'admin' ? '/admin/productos' : '/');
    navigate(targetPath, { replace: true });
  };

  return (
    <main className="min-h-[calc(100vh-4rem)] flex items-center justify-center px-4 py-10 bg-gray-50">
      <section className="w-full max-w-md rounded-2xl bg-white p-6 shadow" aria-label="Formulario de inicio de sesiÃ³n">
        <h1 className="text-2xl font-bold text-gray-900 mb-2">{t('common.login')}</h1>
        <p className="text-sm text-gray-500 mb-6">{t('common.accessToProducts')}</p>

        <form onSubmit={handleSubmit} className="flex flex-col gap-4" noValidate>
          <div className="flex flex-col gap-1">
            <label htmlFor="email" className="text-sm font-medium text-gray-700">{t('common.email')}</label>
            <input
              id="email"
              type="email"
              name="email"
              autoComplete="email"
              value={form.email}
              onChange={(e) => {
                const nextValue = e.target.value;
                setForm((prev) => ({ ...prev, email: nextValue }));
                if (touched.email) {
                  setFieldErrors((prev) => ({ ...prev, email: validateField('email', nextValue) }));
                }
                if (error) setError('');
              }}
              onBlur={(e) => {
                const nextValue = e.target.value;
                setTouched((prev) => ({ ...prev, email: true }));
                setFieldErrors((prev) => ({ ...prev, email: validateField('email', nextValue) }));
              }}
              className={`rounded-lg border px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 ${
                touched.email && fieldErrors.email ? 'border-red-400' : 'border-gray-300'
              }`}
              disabled={isSubmitting}
              aria-invalid={Boolean(touched.email && fieldErrors.email)}
              aria-describedby={touched.email && fieldErrors.email ? 'email-error' : undefined}
              required
            />
            {touched.email && fieldErrors.email && (
              <p id="email-error" className="text-xs text-red-600" role="alert">{fieldErrors.email}</p>
            )}
          </div>

          <div className="flex flex-col gap-1">
            <label htmlFor="password" className="text-sm font-medium text-gray-700">{t('common.password')}</label>
            <input
              id="password"
              type={showPassword ? 'text' : 'password'}
              name="password"
              autoComplete="current-password"
              value={form.password}
              onChange={(e) => {
                const nextValue = e.target.value;
                setForm((prev) => ({ ...prev, password: nextValue }));
                if (touched.password) {
                  setFieldErrors((prev) => ({ ...prev, password: validateField('password', nextValue) }));
                }
                if (error) setError('');
              }}
              onBlur={(e) => {
                const nextValue = e.target.value;
                setTouched((prev) => ({ ...prev, password: true }));
                setFieldErrors((prev) => ({ ...prev, password: validateField('password', nextValue) }));
              }}
              className={`rounded-lg border px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 ${
                touched.password && fieldErrors.password ? 'border-red-400' : 'border-gray-300'
              }`}
              disabled={isSubmitting}
              minLength={8}
              aria-invalid={Boolean(touched.password && fieldErrors.password)}
              aria-describedby={touched.password && fieldErrors.password ? 'password-error' : undefined}
              required
            />
            <button
              type="button"
              onClick={() => setShowPassword((prev) => !prev)}
              className="mt-1 text-xs text-indigo-600 hover:text-indigo-700 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600 w-fit"
              aria-label={showPassword ? t('common.hidePassword') : t('common.showPassword')}
            >
              {showPassword ? t('common.hidePassword') : t('common.showPassword')}
            </button>
            {touched.password && fieldErrors.password && (
              <p id="password-error" className="text-xs text-red-600" role="alert">{fieldErrors.password}</p>
            )}
          </div>

          {error && (
            <p className="text-sm text-red-600" role="alert">{error}</p>
          )}

          <label className="flex items-center gap-2 text-sm text-gray-600 cursor-pointer select-none">
            <input
              type="checkbox"
              checked={rememberEmail}
              onChange={(e) => setRememberEmail(e.target.checked)}
              disabled={isSubmitting}
              className="h-4 w-4 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500"
            />
            {t('common.rememberEmail')}
          </label>

          <button
            type="submit"
            disabled={isSubmitting}
            className="rounded-lg bg-indigo-600 px-4 py-2.5 text-sm font-semibold text-white transition hover:bg-indigo-700 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
          >
            {isSubmitting ? t('common.signingIn') : t('common.signIn')}
          </button>
        </form>

        <p className="mt-4 text-sm text-gray-600">
          <Link
            to="/recuperar"
            className="font-medium text-indigo-600 underline underline-offset-2 hover:text-indigo-700"
          >
            {t('common.forgotPassword')}
          </Link>
        </p>

        <p className="mt-5 text-sm text-gray-600">
          {t('common.dontHaveAccount')}{' '}
          <Link
            to="/registro"
            className="font-medium text-indigo-600 underline underline-offset-2 hover:text-indigo-700"
          >
            {t('common.register')}
          </Link>
        </p>
      </section>
    </main>
  );
}
